active"class="form-label">Status</label><selectclass="form-select"id="is_active"name="is_active"><optionvalue="1">Aktif</option><optionvalue="0">Non-aktif</option></select></div></form></div><divclass="modal-footer"><buttontype="button"class="btnbtn-secondary"data-bs-dismiss="modal">Batal</button><buttontype="button"class="btnbtn-primary"onclick="saveJabatan()">Simpan</button></div></div></div></div><divclass="containermt-4"><divclass="row"><divclass="col-12"><h2><iclass="fasfa-usersme-2"></i>DataPersonilPOLRESSamosir</h2><pclass="text-mutedmb-4">Datapersonilterorganisirberdasarkanbagian/bidang</p><!--MetadataInfo--><divclass="rowmb-4"><divclass="col-lg-8"><divclass="cardborder-primary"><divclass="card-headerbg-primarytext-white"><h5class="card-titlemb-0"><iclass="fasfa-info-circleme-2"></i>InformasiData</h5></div><divclass="card-body"><divclass="row"><divclass="col-md-6"><p><strong>SumberData:</strong>DatabaseMySQL</p><p><strong>TotalBagian:</strong><?phpecho$personnelStats['total_sections'];?>bagian</p></div><divclass="col-md-6"><p><strong>TotalPersonil:</strong><?phpecho$personnelStats['total_personnel'];?>orang</p><p><strong>TerakhirUpdate:</strong><?phpechodate('dFYH:i:s');?></p></div></div><pclass="text-mutedmt-2">DatapersonildaridatabasesistemPOLRESSamosir</p></div></div></div><divclass="col-lg-4"><divclass="cardborder-success"><divclass="card-headerbg-successtext-white"><h5class="card-titlemb-0"><iclass="fasfa-chart-barme-2"></i>Statistik</h5></div><divclass="card-body"><divclass="rowtext-center"><divclass="col-6"><divclass="h4text-success"><?phpecho$personnelStats['total_sections'];?></div><smallclass="text-muted">Bagian</small></div><divclass="col-6"><divclass="h4text-primary"><?phpecho$personnelStats['total_personnel'];?></div><smallclass="text-muted">Personil</small></div></div></div></div></div></div><!--AccordionControls--><divclass="d-flexjustify-content-betweenalign-items-centermb-3"><h4class="mb-0">DataPersonilperBagian</h4><divclass="d-flexgap-2"><buttonclass="btnbtn-outline-primarybtn-sm"onclick="expandAll()"><iclass="fasfa-expand-altme-1"></i>ExpandAll</button><buttonclass="btnbtn-outline-secondarybtn-sm"onclick="collapseAll()"><iclass="fasfa-compress-altme-1"></i>CollapseAll</button></div></div><!--PersonnelAccordion--><divclass="accordion"id="personnelAccordion"><?phpif(empty($personnelData)):?><divclass="alertalert-warning"><iclass="fasfa-exclamation-triangleme-2"></i>Belumadadatapersonildidatabase.</div><?phpelse:?><?phpforforeach($personnelDataas$index=>$section):?><divclass="accordion-item"><h2class="accordion-header"id="heading-personnel-<?phpecho$index;?>"><buttonclass="accordion-button<?phpecho$index===0?'':'collapsed';?>"type="button"data-bs-toggle="collapse"data-bs-target="#collapse-personnel-<?phpecho$index;?>"aria-expanded="<?phpecho$index===0?'true':'false';?>"aria-controls="collapse-personnel-<?phpecho$index;?>"><divclass="d-flexjustify-content-betweenalign-items-centerw-100"><divclass="text-start"><iclass="fasfa-buildingme-2"></i><strong><?phpechohtmlspecialchars($section['section_name']);?></strong><divclass="smalltext-mutedmt-1"><?phpecho$section['personnel_count'];?>Personil</div></div><divclass="badgebg-primaryme-3"><?phpecho$section['personnel_count'];?>orang</div></div></button></h2><divid="collapse-personnel-<?phpecho$index;?>"class="accordion-collapsecollapse<?phpecho$index===0?'show':'';?>"aria-labelledby="heading-personnel-<?phpecho$index;?>"><divclass="accordion-bodyp-0"><?phpif(!empty($section['personnel'])):?><divclass="table-responsive"><tableclass="tabletable-stripedtable-hovermb-0"><theadclass="table-dark"><tr><thwidth="5%">No</th><thwidth="35%">Nama</th><thwidth="15%">Pangkat</th><thwidth="15%">NRP</th><thwidth="25%">Jabatan</th><thwidth="5%">Ket</th></tr></thead><tbody><?php$counter=1;?><?phpforforeach($section['personnel']as$person):?><tr><tdclass="text-center"><?phpecho$counter++;?></td><td><strong><?phpechohtmlspecialchars($person['nama']??'-');?></strong></td><td><spanclass="badgebg-secondary"><?phpechohtmlspecialchars($person['pangkat']??'-');?></span></td><tdclass="font-monospacesmall"><?phpechohtmlspecialchars($person['nrp']??'-');?></td><td><?phpechohtmlspecialchars($person['jabatan']??'-');?></td><td><?phpif(!empty($person['ket'])):?><smallclass="text-muted"><?phpechohtmlspecialchars($person['ket']);?></small><?phpelse:?><spanclass="text-muted">-</span><?phpendif;?></td></tr><?phpendforeach;?></tbody></table></div><?phpelse:?><divclass="alertalert-warningm-3"><iclass="fasfa-exclamation-triangleme-2"></i>Tidakadadatapersoniluntukbagianini.</div><?phpendif;?></div></div></div><?phpendforeach;?><?phpendif;?></div></div></div></div><script>/AccordioncontrolfunctionsfunctionexpandAll(){constbuttons=document.querySelectorAll('#personnelAccordion.accordion-button.collapsed');buttons.forEach(button=>{constcollapse=newbootstrap.Collapse(button.getAttribute('data-bs-target'));collapse.show();});}functioncollapseAll(){constbuttons=document.querySelectorAll('#personnelAccordion.accordion-button:not(.collapsed)');buttons.forEach(button=>{constcollapse=newbootstrap.Collapse(button.getAttribute('data-bs-target'));collapse.hide();});}</script><script>/ModalfunctionsfunctionopenAddModal(){document.getElementById('jabatanModalLabel').textContent='TambahJabatan';document.getElementById('formAction').value='create';document.getElementById('formId').value='';document.getElementById('jabatanForm').reset();newbootstrap.Modal(document.getElementById('jabatanModal')).show();}functionopenAddModalForUnsur(unsurId){document.getElementById('jabatanModalLabel').textContent='TambahJabatan';document.getElementById('formAction').value='create';document.getElementById('formId').value='';document.getElementById('id_unsur').value=unsurId;updateBagianOptions();newbootstrap.Modal(document.getElementById('jabatanModal')).show();}functionopenAddModalForBagian(bagianId){document.getElementById('jabatanModalLabel').textContent='TambahJabatan';document.getElementById('formAction').value='create';document.getElementById('formId').value='';document.getElementById('id_bagian').value=bagianId;newbootstrap.Modal(document.getElementById('jabatanModal')).show();}functioneditJabatan(id){/Loadjabatandataandopenmodalfetch('index.php?phpechoAPI_BASE_URL;'+id).then(response=>response.json()).then(data=>{if(data.success){document.getElementById('jabatanModalLabel').textContent='EditJabatan';document.getElementById('formAction').value='update';document.getElementById('formId').value=id;document.getElementById('nama_jabatan').value=data.jabatan.nama_jabatan;document.getElementById('id_unsur').value=data.jabatan.id_unsur;updateBagianOptions(()=>{document.getElementById('id_bagian').value=data.jabatan.id_bagian;});document.getElementById('is_active').value=data.jabatan.is_active;newbootstrap.Modal(document.getElementById('jabatanModal')).show();}});}functiondeleteJabatan(id){if(confirm('ApakahAndayakininginmenghapusjabatanini?')){fetch('<?phpechoAPI_BASE_URL;?>/v1/jabatan.php',{method:'DELETE',headers:{'Content-Type':'application/json'},body:JSON.stringify({id:id})}).then(response=>response.json()).then(data=>{if(data.success){location.reload();}else{alert('Error:'+data.message);}});}}functionsaveJabatan(){constform=document.getElementById('jabatanForm');constformData=newFormData(form);constaction=formData.get('action');constid=formData.get('id');constdata={action:action,id:id,nama_jabatan:formData.get('nama_jabatan'),id_unsur:formData.get('id_unsur'),id_bagian:formData.get('id_bagian'),is_active:formData.get('is_active')};consturl='<?phpechoAPI_BASE_URL;?>/v1/jabatan.php';constmethod=action==='create'?'POST':'PUT';fetch(url,{method:method,headers:{'Content-Type':'application/json'},body:JSON.stringify(data)}).then(response=>response.json()).then(data=>{if(data.success){bootstrap.Modal.getInstance(document.getElementById('jabatanModal')).hide();location.reload();}else{alert('Error:'+data.message);}});}functionupdateBagianOptions(callback){constunsurId=document.getElementById('id_unsur').value;constbagianSelect=document.getElementById('id_bagian');bagianSelect.innerHTML='<optionvalue="">PilihBagian</option>';if(unsurId){fetch('index.php?phpechoAPI_BASE_URL;'+unsurId).then(response=>response.json()).then(data=>{if(data.success){data.bagians.forEach(bagian=>{constoption=document.createElement('option');option.value=bagian.id;option.textContent=bagian.nama_bagian;bagianSelect.appendChild(option);});if(callback)callback();}});}}/Updatebagianoptionswhenunsurchangesdocument.getElementById('id_unsur').addEventListener('change',updateBagianOptions);</script><?phpinclude__DIR__.'/../includes/components/footer.php';?>
